Add-Type -AssemblyName System.Drawing; $bmp=[System.Drawing.Bitmap]::FromFile("d:\project\wingezi\shots\spotlight.png"); $w=$bmp.Width;$h=$bmp.Height; $rect=New-Object System.Drawing.Rectangle 0,0,$w,$h; $data=$bmp.LockBits($rect,[System.Drawing.Imaging.ImageLockMode]::ReadOnly,[System.Drawing.Imaging.PixelFormat]::Format32bppArgb); $stride=$data.Stride; $bytes=New-Object byte[] ($stride*$h); [System.Runtime.InteropServices.Marshal]::Copy($data.Scan0,$bytes,0,$bytes.Length); $bmp.UnlockBits($data); $bmp.Dispose()
foreach($y in 132,140){ $runs=@(); $inRun=$false; $start=0; for($x=0;$x -lt $w;$x++){ $i=$y*$stride+$x*4; $r=$bytes[$i+2];$g=$bytes[$i+1];$b=$bytes[$i]; $isFill=($r -ge 50 -and $r -le 70 -and ($r-$b) -lt 8 -and ($r-$g) -lt 8); if($isFill -and -not $inRun){$inRun=$true;$start=$x}; if((-not $isFill) -and $inRun){$inRun=$false;$runs+=("$start-" + ($x-1) + "(w" + ($x-$start) + ")")} }; if($inRun){$runs+=("$start-" + ($w-1))}; Write-Output ("y=" + $y + " runs: " + ($runs -join ", ")) }
$c1=0;$c2=0;$c3=0;$oYmin=999;$oYmax=-1; for($y=0;$y -lt $h;$y++){ for($x=0;$x -lt $w;$x++){ $i=$y*$stride+$x*4; $r=$bytes[$i+2];$g=$bytes[$i+1];$b=$bytes[$i]; if($r -gt 195 -and $g -gt 85 -and $g -lt 165 -and $b -lt 135 -and $r -gt $g){ if($x -lt 220){$c1++} elseif($x -lt 424){$c2++} else {$c3++}; if($y -lt $oYmin){$oYmin=$y}; if($y -gt $oYmax){$oYmax=$y} } } }; Write-Output ("BrightOrange btn1=" + $c1 + " btn2=" + $c2 + " btn3=" + $c3 + " yRange=" + $oYmin + "-" + $oYmax)
foreach($x in 60,260,470){ $top=-1;$bot=-1; for($y=80;$y -lt 220;$y++){ $i=$y*$stride+$x*4; $r=$bytes[$i+2];$g=$bytes[$i+1];$b=$bytes[$i]; $isFill=($r -ge 50 -and $r -le 70 -and ($r-$b) -lt 8 -and ($r-$g) -lt 8); if($isFill -and $top -lt 0){$top=$y}; if($isFill){$bot=$y} }; Write-Output ("x=" + $x + " button vertical: top=" + $top + " bot=" + $bot + " (h=" + ($bot-$top+1) + ")") }
